 1	import { useActivePerspective } from '@openshift-console/dynamic-plugin-sdk';
 2	import { Button, Flex, FlexItem, Stack, StackItem, Title } from '@patternfly/react-core';
 3	import { TimesCircleIcon } from '@patternfly/react-icons';
 4	import * as React from 'react';
 5	import { useTranslation } from 'react-i18next';
 6	import { useDispatch, useSelector } from 'react-redux';
 7	import { closeTP } from '../redux-actions';
 8	import { State } from '../redux-reducers';
 9	import { HelpPopover } from './HelpPopover';
10	import Korrel8rPanel from './Korrel8rPanel';
11	import './popover.css';
12	
13	export default function Popover() {
14	  const dispatch = useDispatch();
15	  const [activePerspective] = useActivePerspective();
16	  const { t } = useTranslation('plugin__troubleshooting-panel-console-plugin');
17	
18	  const isOpen = useSelector((state: State) => state.plugins?.tp?.get('isOpen'));
19	
20	  const close = React.useCallback(() => {
21	    dispatch(closeTP());
22	  }, [dispatch]);
23	
24	  React.useEffect(() => {
25	    if (activePerspective !== 'admin' && isOpen) {
26	      close();
27	    }
28	  }, [activePerspective, isOpen, close]);
29	
30	  if (!isOpen) {
31	    return null;
32	  }
33	
34	  return (
35	    <>
36	      <Stack className="tp-plugin__popover">
37	        <Flex className="tp-plugin__popover-title-bar" gap={{ default: 'gapNone' }}>
38	          <FlexItem grow={{ default: 'grow' }}>
39	            <Title headingLevel="h1">
40	              {t('Troubleshooting')}
41	              <HelpPopover
42	                header={t(
43	                  'Quickly diagnose and resolve issues by exploring correlated observability signals for resources.',
44	                )}
45	              ></HelpPopover>
46	            </Title>
47	          </FlexItem>
48	          <FlexItem>
49	            <Button variant="plain" aria-label="Close" onClick={close}>
50	              <TimesCircleIcon className="tp-plugin__popover-close" />
51	            </Button>
52	          </FlexItem>
53	        </Flex>
54	        <StackItem className="tp-plugin__popover-content" isFilled={true}>
55	          <Korrel8rPanel />
56	        </StackItem>
57	      </Stack>
58	    </>
59	  );
60	}

